package com.example.secondphone.entity;import jakarta.persistence.AttributeConverter;import jakarta.persistence.Converter;@Converter public class MemberRoleConverter implements AttributeConverter<MemberRole,String>{public String convertToDatabaseColumn(MemberRole role){return role==null?null:role.name();}public MemberRole convertToEntityAttribute(String value){if(value==null)return MemberRole.CUSTOMER;return "USER".equalsIgnoreCase(value)?MemberRole.CUSTOMER:MemberRole.valueOf(value.toUpperCase());}}
